class Solution(object):
    def maxArea(self, height):
        len_height = len(height)
        l = 0
        r = len_height - 1
        max_s = 0
        while l <= r:
            new_s = min(height[l], height[r]) * (r - l)
            if new_s > max_s:
                max_s = new_s
            if height[l] < height[r]:
                l += 1
            else:
                r -= 1
        return max_s
